use aiken/collection/list
use aiken/crypto
use aiken/primitive/string

pub type JoinDatum {
  parts: List<ByteArray>,
  separator: ByteArray,
  expected_hash: ByteArray,
}

fn verify_join(datum: JoinDatum) -> Bool {
  let sep = string.from_bytearray(datum.separator)
  let string_parts = list.map(datum.parts, string.from_bytearray)
  let joined = string.join(string_parts, sep)
  let joined_bytes = string.to_bytearray(joined)
  let actual_hash = crypto.sha2_256(joined_bytes)
  actual_hash == datum.expected_hash
}

validator join_validator {
  spend(
    datum: Option<JoinDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> verify_join(d)
    }
  }
}

