use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type TraceDatum {
  owner: ByteArray,
  amount: Int,
}

validator trace_validator {
  spend(
    datum: Option<TraceDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let amount_str = string.from_int(d.amount)
        let owner_str = string.from_bytearray(d.owner)
        let msg =
          string.concat(
            string.concat(
              string.concat(@"owner: ", owner_str),
              string.concat(@" amount: ", amount_str),
            ),
            @" spending trace",
          )
        trace msg
        let owner_signed =
          list.any(
            self.extra_signatories,
            fn(sig) { sig == d.owner },
          )
        owner_signed
      }
    }
  }
}

use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type RegistryDatum {
  id: Int,
  owner: ByteArray,
}

fn owner_signed(tx: Transaction, owner: ByteArray) -> Bool {
  let signatories = tx.extra_signatories
  list.any(signatories, fn(sig) { sig == owner })
}

validator labeled_registry(label_prefix: ByteArray) {
  spend(
    datum: Option<RegistryDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let _label =
          string.concat(
            string.from_bytearray(label_prefix),
            string.from_int(d.id),
          )
        owner_signed(self, d.owner)
      }
    }
  }
}

use aiken/collection/list

use aiken/primitive/string

pub type NameDatum {
  name_bytes: ByteArray,
  min_len: Int,
}

validator name_length_check {
  spend(
    datum: Option<NameDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let name_str = string.from_bytearray(d.name_bytes)
        let name_back = string.to_bytearray(name_str)
        let length = builtin.length_of_bytearray(name_back)
        length >= d.min_len
      }
    }
  }
}
